     1→<?php
     2→/**
     3→ * Plugin Name: AgentPress
     4→ * Plugin URI: https://emdash.com/agentpress
     5→ * Description: AI-powered content and image generation for WordPress. Built-in agents for content writing and image generation.
     6→ * Version: 1.0.0
     7→ * Author: Emdash
     8→ * Author URI: https://emdash.com
     9→ * License: GPL v2 or later
    10→ * License URI: https://www.gnu.org/licenses/gpl-2.0.html
    11→ * Text Domain: agentpress
    12→ * Domain Path: /languages
    13→ * Requires at least: 6.0
    14→ * Requires PHP: 8.0
    15→ */
    16→
    17→// Prevent direct access
    18→if (!defined('ABSPATH')) {
    19→    exit;
    20→}
    21→
    22→// Define plugin constants
    23→define('AGENTPRESS_VERSION', '1.0.0');
    24→define('AGENTPRESS_PLUGIN_DIR', plugin_dir_path(__FILE__));
    25→define('AGENTPRESS_PLUGIN_URL', plugin_dir_url(__FILE__));
    26→define('AGENTPRESS_PLUGIN_BASENAME', plugin_basename(__FILE__));
    27→
    28→/**
    29→ * Get a plugin setting with wp-config constant fallback.
    30→ *
    31→ * @param string $key Setting key.
    32→ * @param mixed $default Default value if not set.
    33→ * @return mixed Setting value.
    34→ */
    35→function agentpress_get_setting($key, $default = null) {
    36→    $settings = get_option('agentpress_settings', array());
    37→
    38→    // Check for wp-config constant override first
    39→    $constant_map = array(
    40→        'claude_api_key' => 'AGENTPRESS_CLAUDE_KEY',
    41→        'cf_worker_url' => 'AGENTPRESS_CF_WORKER_URL',
    42→        'default_model' => 'AGENTPRESS_DEFAULT_MODEL',
    43→    );
    44→
    45→    if (isset($constant_map[$key]) && defined($constant_map[$key])) {
    46→        return constant($constant_map[$key]);
    47→    }
    48→
    49→    return isset($settings[$key]) ? $settings[$key] : $default;
    50→}
    51→
    52→/**
    53→ * Register custom post types for capabilities and logs.
    54→ */
    55→function agentpress_register_cpts() {
    56→    // Register agentpress_capability CPT
    57→    register_post_type('agentpress_capability', array(
    58→        'labels' => array(
    59→            'name' => __('AgentPress Capabilities', 'agentpress'),
    60→            'singular_name' => __('AgentPress Capability', 'agentpress'),
    61→        ),
    62→        'public' => false,
    63→        'show_ui' => false,
    64→        'show_in_menu' => false,
    65→        'show_in_rest' => false,
    66→        'capability_type' => 'post',
    67→        'supports' => array('title'),
    68→        'has_archive' => false,
    69→        'rewrite' => false,
    70→        'query_var' => false,
    71→    ));
    72→
    73→    // Register agentpress_log CPT
    74→    register_post_type('agentpress_log', array(
    75→        'labels' => array(
    76→            'name' => __('AgentPress Logs', 'agentpress'),
    77→            'singular_name' => __('AgentPress Log', 'agentpress'),
    78→        ),
    79→        'public' => false,
    80→        'show_ui' => true,
    81→        'show_in_menu' => false,
    82→        'show_in_rest' => false,
    83→        'capability_type' => 'post',
    84→        'supports' => array('title'),
    85→        'has_archive' => false,
    86→        'rewrite' => false,
    87→        'query_var' => false,
    88→        'revision' => false,
    89→        'autosave' => false,
    90→    ));
    91→}
    92→add_action('init', 'agentpress_register_cpts');
    93→
    94→/**
    95→ * Seed built-in capabilities on activation.
    96→ */
    97→function agentpress_seed_capabilities() {
    98→    $capabilities = array(
    99→        array(
   100→            'slug' => 'content_writer',
   101→            'title' => 'Content Writer',
   102→            'description' => 'Generates written content using Claude API.',
   103→        ),
   104→        array(
   105→            'slug' => 'image_generator',
   106→            'title' => 'Image Generator',
   107→            'description' => 'Generates images using Cloudflare Workers AI.',
   108→        ),
   109→    );
   110→
   111→    foreach ($capabilities as $cap) {
   112→        // Check if capability already exists
   113→        $existing = get_posts(array(
   114→            'post_type' => 'agentpress_capability',
   115→            'name' => $cap['slug'],
   116→            'posts_per_page' => 1,
   117→            'post_status' => 'any',
   118→        ));
   119→
   120→        if (empty($existing)) {
   121→            wp_insert_post(array(
   122→                'post_type' => 'agentpress_capability',
   123→                'post_title' => $cap['title'],
   124→                'post_name' => $cap['slug'],
   125→                'post_status' => 'publish',
   126→                'meta_input' => array(
   127→                    '_capability_slug' => $cap['slug'],
   128→                    '_capability_description' => $cap['description'],
   129→                ),
   130→            ));
   131→        }
   132→    }
   133→}
   134→
   135→/**
   136→ * Create default settings option.
   137→ */
   138→function agentpress_create_default_settings() {
   139→    $default_settings = array(
   140→        'default_model' => 'claude-3-5-sonnet-20241022',
   141→        'claude_api_key' => '',
   142→        'cf_worker_url' => '',
   143→    );
   144→
   145→    if (get_option('agentpress_settings') === false) {
   146→        add_option('agentpress_settings', $default_settings);
   147→    }
   148→}
   149→
   150→/**
   151→ * Plugin activation hook.
   152→ */
   153→function agentpress_activate() {
   154→    // Register CPTs so we can create posts
   155→    agentpress_register_cpts();
   156→
   157→    // Flush rewrite rules
   158→    flush_rewrite_rules();
   159→
   160→    // Seed built-in capabilities
   161→    agentpress_seed_capabilities();
   162→
   163→    // Create default settings
   164→    agentpress_create_default_settings();
   165→}
   166→register_activation_hook(__FILE__, 'agentpress_activate');
   167→
   168→/**
   169→ * Plugin deactivation hook.
   170→ */
   171→function agentpress_deactivate() {
   172→    // Flush rewrite rules on deactivation
   173→    flush_rewrite_rules();
   174→}
   175→register_deactivation_hook(__FILE__, 'agentpress_deactivate');
   176→
   177→/**
   178→ * Autoloader for AgentPress classes.
   179→ *
   180→ * @param string $class Class name to load.
   181→ */
   182→function agentpress_autoloader($class) {
   183→    // Only handle AgentPress namespace
   184→    if (strpos($class, 'AgentPress\\') !== 0) {
   185→        return;
   186→    }
   187→
   188→    // Remove namespace prefix
   189→    $class_name = str_replace('AgentPress\\', '', $class);
   190→
   191→    // Define class file mappings
   192→    $class_map = array(
   193→        'Parser' => 'includes/class-parser.php',
   194→        'Agents' => 'includes/class-agents.php',
   195→        'Logger' => 'includes/class-logger.php',
   196→        'Router' => 'includes/class-router.php',
   197→        'REST_API' => 'includes/class-rest-api.php',
   198→        'Admin' => 'admin/class-admin.php',
   199→        'Content_Writer' => 'includes/agents/class-content-writer.php',
   200→        'Image_Generator' => 'includes/agents/class-image-generator.php',
   201→    );
   202→
   203→    // Handle sub-namespaces like AgentPress\Agents\Content_Writer
   204→    if (strpos($class_name, '\\') !== false) {
   205→        $parts = explode('\\', $class_name);
   206→        $sub_namespace = strtolower($parts[0]);
   207→        $class_name = $parts[1];
   208→
   209→        $file = AGENTPRESS_PLUGIN_DIR . 'includes/' . $sub_namespace . '/class-' . strtolower(str_replace('_', '-', $class_name)) . '.php';
   210→    } else {
   211→        $file = AGENTPRESS_PLUGIN_DIR . (isset($class_map[$class_name]) ? $class_map[$class_name] : '');
   212→    }
   213→
   214→    if (file_exists($file)) {
   215→        require_once $file;
   216→    }
   217→}
   218→spl_autoload_register('agentpress_autoloader');
   219→
   220→/**
   221→ * Initialize core classes on plugins_loaded.
   222→ */
   223→function agentpress_init() {
   224→    // Initialize REST API
   225→    if (class_exists('AgentPress\\REST_API')) {
   226→        new AgentPress\REST_API();
   227→    }
   228→
   229→    // Initialize Admin
   230→    if (is_admin() && class_exists('AgentPress\\Admin')) {
   231→        new AgentPress\Admin();
   232→    }
   233→}
   234→add_action('plugins_loaded', 'agentpress_init');
   235→
   236→/**
   237→ * Register REST API routes.
   238→ */
   239→function agentpress_register_rest_routes() {
   240→    if (class_exists('AgentPress\\REST_API')) {
   241→        AgentPress\REST_API::register_routes();
   242→    }
   243→}
   244→add_action('rest_api_init', 'agentpress_register_rest_routes');
   245→

