     1→<?php
     2→/**
     3→ * AgentPress Activity Logger
     4→ *
     5→ * Logs agent executions to custom post type with auto-pruning.
     6→ *
     7→ * @package AgentPress
     8→ * @since 1.0.0
     9→ */
    10→
    11→namespace AgentPress;
    12→
    13→/**
    14→ * Logger class for activity logging with auto-prune.
    15→ */
    16→class Logger {
    17→
    18→    /**
    19→     * Maximum number of log entries to keep.
    20→     *
    21→     * @var int
    22→     */
    23→    const MAX_LOGS = 500;
    24→
    25→    /**
    26→     * Number of entries to prune when over max.
    27→     *
    28→     * @var int
    29→     */
    30→    const PRUNE_COUNT = 50;
    31→
    32→    /**
    33→     * Log an agent execution.
    34→     *
    35→     * @param string $capability Capability slug.
    36→     * @param string $task Original task description.
    37→     * @param string $status Execution status (success, error).
    38→     * @param int $latency_ms Execution time in milliseconds.
    39→     * @param array $result Result data from agent.
    40→     * @param array $routing Routing information.
    41→     * @return int|WP_Error Log post ID or WP_Error on failure.
    42→     */
    43→    public static function log($capability, $task, $status, $latency_ms, $result = array(), $routing = array()) {
    44→        $post_data = array(
    45→            'post_type' => 'agentpress_log',
    46→            'post_title' => sprintf('%s - %s', $capability, wp_trim_words($task, 10)),
    47→            'post_status' => 'publish',
    48→        );
    49→
    50→        $post_id = wp_insert_post($post_data, true);
    51→
    52→        if (is_wp_error($post_id)) {
    53→            return $post_id;
    54→        }
    55→
    56→        // Store meta fields
    57→        update_post_meta($post_id, '_agentpress_capability', $capability);
    58→        update_post_meta($post_id, '_agentpress_task', $task);
    59→        update_post_meta($post_id, '_agentpress_status', $status);
    60→        update_post_meta($post_id, '_agentpress_latency_ms', (int) $latency_ms);
    61→        update_post_meta($post_id, '_agentpress_result', maybe_serialize($result));
    62→        update_post_meta($post_id, '_agentpress_routing_source', isset($routing['source']) ? $routing['source'] : '');
    63→        update_post_meta($post_id, '_agentpress_timestamp', current_time('mysql'));
    64→
    65→        // Auto-prune after logging
    66→        self::prune();
    67→
    68→        return $post_id;
    69→    }
    70→
    71→    /**
    72→     * Prune old log entries when count exceeds max.
    73→     *
    74→     * Deletes oldest PRUNE_COUNT entries when count > MAX_LOGS.
    75→     *
    76→     * @return int Number of entries pruned.
    77→     */
    78→    public static function prune() {
    79→        $count = self::get_log_count();
    80→
    81→        if ($count <= self::MAX_LOGS) {
    82→            return 0;
    83→        }
    84→
    85→        $to_delete = $count - self::MAX_LOGS;
    86→        if ($to_delete < self::PRUNE_COUNT) {
    87→            $to_delete = self::PRUNE_COUNT;
    88→        }
    89→
    90→        // Get oldest log IDs
    91→        $old_logs = get_posts(array(
    92→            'post_type' => 'agentpress_log',
    93→            'posts_per_page' => $to_delete,
    94→            'orderby' => 'date',
    95→            'order' => 'ASC',
    96→            'fields' => 'ids',
    97→            'post_status' => 'any',
    98→        ));
    99→
   100→        $pruned = 0;
   101→        foreach ($old_logs as $log_id) {
   102→            wp_delete_post($log_id, true);
   103→            $pruned++;
   104→        }
   105→
   106→        return $pruned;
   107→    }
   108→
   109→    /**
   110→     * Get recent log entries.
   111→     *
   112→     * @param int $limit Number of entries to retrieve.
   113→     * @return array Array of log entry data.
   114→     */
   115→    public static function get_recent($limit = 50) {
   116→        $logs = get_posts(array(
   117→            'post_type' => 'agentpress_log',
   118→            'posts_per_page' => $limit,
   119→            'orderby' => 'date',
   120→            'order' => 'DESC',
   121→            'post_status' => 'any',
   122→        ));
   123→
   124→        $result = array();
   125→        foreach ($logs as $log) {
   126→            $result[] = array(
   127→                'id' => $log->ID,
   128→                'title' => $log->post_title,
   129→                'date' => $log->post_date,
   130→                'capability' => get_post_meta($log->ID, '_agentpress_capability', true),
   131→                'status' => get_post_meta($log->ID, '_agentpress_status', true),
   132→                'latency_ms' => get_post_meta($log->ID, '_agentpress_latency_ms', true),
   133→                'task' => get_post_meta($log->ID, '_agentpress_task', true),
   134→                'routing_source' => get_post_meta($log->ID, '_agentpress_routing_source', true),
   135→            );
   136→        }
   137→
   138→        return $result;
   139→    }
   140→
   141→    /**
   142→     * Get total log count.
   143→     *
   144→     * @return int Number of log entries.
   145→     */
   146→    public static function get_log_count() {
   147→        $count = wp_count_posts('agentpress_log');
   148→        return $count->publish + $count->draft + $count->private;
   149→    }
   150→
   151→    /**
   152→     * Get a single log entry by ID.
   153→     *
   154→     * @param int $log_id Log post ID.
   155→     * @return array|null Log entry data or null if not found.
   156→     */
   157→    public static function get_log($log_id) {
   158→        $log = get_post($log_id);
   159→        if (!$log || $log->post_type !== 'agentpress_log') {
   160→            return null;
   161→        }
   162→
   163→        return array(
   164→            'id' => $log->ID,
   165→            'title' => $log->post_title,
   166→            'date' => $log->post_date,
   167→            'capability' => get_post_meta($log->ID, '_agentpress_capability', true),
   168→            'status' => get_post_meta($log->ID, '_agentpress_status', true),
   169→            'latency_ms' => get_post_meta($log->ID, '_agentpress_latency_ms', true),
   170→            'task' => get_post_meta($log->ID, '_agentpress_task', true),
   171→            'result' => maybe_unserialize(get_post_meta($log->ID, '_agentpress_result', true)),
   172→            'routing_source' => get_post_meta($log->ID, '_agentpress_routing_source', true),
   173→        );
   174→    }
   175→
   176→    /**
   177→     * Clear all logs.
   178→     *
   179→     * @return int Number of logs deleted.
   180→     */
   181→    public static function clear_all() {
   182→        $logs = get_posts(array(
   183→            'post_type' => 'agentpress_log',
   184→            'posts_per_page' => -1,
   185→            'fields' => 'ids',
   186→            'post_status' => 'any',
   187→        ));
   188→
   189→        $deleted = 0;
   190→        foreach ($logs as $log_id) {
   191→            wp_delete_post($log_id, true);
   192→            $deleted++;
   193→        }
   194→
   195→        return $deleted;
   196→    }
   197→}
